</head>
<body>
<div id="app">
  <h1>Expenses</h1>
  <form id="form">
    <input id="desc" placeholder="Description">
    <input id="amount" type="number" step="0.01" min="0" placeholder="0.00">
    <button id="add" type="submit">Add</button>
  </form>
  <ul id="entries"></ul>
